import XCTest
@testable import pycashflow

/// Verifies the standalone Demo-mode projection engine against ground-truth
/// vectors captured from the real PyCashFlow backend (`app/cashflow.py`).
///
/// Each vector fixes `today` so the assertions are deterministic regardless of
/// when the suite runs. The engine was additionally fuzz-verified field-for-
/// field against the backend across tens of thousands of randomized cases while
/// developing this port; these embedded cases guard against regressions.
final class DemoProjectionTests: XCTestCase {

    // MARK: Vector decoding

    private struct VectorFile: Decodable { let today: String; let cases: [Case] }
    private struct Case: Decodable {
        let name: String
        let balance: String
        let schedules: [Item]
        let scenarios: [Item]
        let holds: [Hold]
        let skips: [Skip]
        let expected: Expected
    }
    private struct Item: Decodable {
        let name: String; let start_date: String; let frequency: String
        let amount: String; let type: String
    }
    private struct Hold: Decodable { let name: String; let amount: String; let type: String }
    private struct Skip: Decodable { let name: String; let date: String; let amount: String; let type: String }
    private struct Expected: Decodable {
        let min_balance: String
        let schedule: [Point]
        let scenario: [Point]?
        let upcoming: [Tx]
        let risk: Risk
    }
    private struct Point: Decodable { let date: String; let amount: String }
    private struct Tx: Decodable { let name: String; let type: String; let amount: String; let date: String }
    private struct Risk: Decodable {
        let score: Int; let status: String; let runway_days: Double?; let lowest_balance: String
    }

    func testEngineMatchesBackendVectors() throws {
        let file = try JSONDecoder().decode(VectorFile.self, from: Data(vectorsJSON.utf8))
        let today = try XCTUnwrap(DemoDate.parse(file.today), "bad today")

        for c in file.cases {
            let balance = try XCTUnwrap(Decimal(string: c.balance, locale: posix), "bad balance in \(c.name)")
            let schedules = try c.schedules.map { try item($0) }
            let scenarios = try c.scenarios.map { try item($0) }
            let holds = c.holds.map {
                DemoProjectionEngine.HoldInput(name: $0.name, amount: dec($0.amount), type: $0.type)
            }
            let skips = try c.skips.map { s -> DemoProjectionEngine.SkipInput in
                DemoProjectionEngine.SkipInput(
                    name: s.name, date: try XCTUnwrap(DemoDate.parse(s.date)),
                    amount: dec(s.amount), type: s.type)
            }

            let result = DemoProjectionEngine.project(
                balance: balance, schedules: schedules, scenarios: scenarios,
                holds: holds, skips: skips, today: today)

            // min_balance
            XCTAssertEqual(result.minBalance, c.expected.min_balance, "min_balance [\(c.name)]")

            // schedule series
            assertSeries(result.scheduleRun, c.expected.schedule, label: "schedule [\(c.name)]")

            // scenario series
            if let expectedScenario = c.expected.scenario {
                let run = try XCTUnwrap(result.scenarioRun, "scenarioRun nil [\(c.name)]")
                assertSeries(run, expectedScenario, label: "scenario [\(c.name)]")
            } else {
                XCTAssertNil(result.scenarioRun, "scenarioRun should be nil [\(c.name)]")
            }

            // upcoming
            XCTAssertEqual(result.upcoming.count, c.expected.upcoming.count, "upcoming count [\(c.name)]")
            for (got, exp) in zip(result.upcoming, c.expected.upcoming) {
                XCTAssertEqual(got.name, exp.name, "upcoming name [\(c.name)]")
                XCTAssertEqual(got.type, exp.type, "upcoming type [\(c.name)]")
                XCTAssertEqual(DemoAmount.string(got.amount), exp.amount, "upcoming amount [\(c.name)]")
                XCTAssertEqual(got.date.isoString, exp.date, "upcoming date [\(c.name)]")
            }

            // risk (the four fields the app displays)
            XCTAssertEqual(result.risk.score, c.expected.risk.score, "risk.score [\(c.name)]")
            XCTAssertEqual(result.risk.status, c.expected.risk.status, "risk.status [\(c.name)]")
            XCTAssertEqual(result.risk.lowestBalance, c.expected.risk.lowest_balance, "risk.lowest [\(c.name)]")
            if let expectedRunway = c.expected.risk.runway_days {
                let got = try XCTUnwrap(result.risk.runwayDays, "runway nil [\(c.name)]")
                XCTAssertEqual(got, expectedRunway, accuracy: 1e-6, "risk.runway [\(c.name)]")
            } else {
                XCTAssertNil(result.risk.runwayDays, "runway should be nil [\(c.name)]")
            }
        }
    }

    // MARK: Helpers

    private let posix = Locale(identifier: "en_US_POSIX")
    private func dec(_ s: String) -> Decimal { Decimal(string: s, locale: posix) ?? 0 }
    private func item(_ i: Item) throws -> DemoProjectionEngine.Item {
        DemoProjectionEngine.Item(
            name: i.name, startDate: try XCTUnwrap(DemoDate.parse(i.start_date)),
            frequency: i.frequency, amount: dec(i.amount), type: i.type)
    }

    private func assertSeries(_ got: [DemoProjectionEngine.SeriesPoint], _ expected: [Point], label: String) {
        XCTAssertEqual(got.count, expected.count, "\(label) count")
        for (g, e) in zip(got, expected) {
            XCTAssertEqual(g.date.isoString, e.date, "\(label) date")
            XCTAssertEqual(DemoAmount.string(fromDouble: g.amount), e.amount, "\(label) amount")
        }
    }
}

